"""
Browser action recorder - connects to existing Chrome via CDP
and records user interactions as replayable Playwright code.

Usage:
    python3 scripts/recorder.py [--cdp http://localhost:9222] [-o recorded_actions.py]

Press Ctrl+C to stop recording.
"""

import asyncio
import json
import sys
import signal
import time
from datetime import datetime
from pathlib import Path

# Add project root to path
sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from patchright.async_api import async_playwright


# JS snippet injected into the page to capture user interactions
RECORDER_JS = """
(() => {
    if (window.__recorder_installed__) return;
    window.__recorder_installed__ = true;

    const events = [];
    const startTime = Date.now();

    function getSelector(el) {
        // Priority 1: data-testid or id
        if (el.id) return '#' + CSS.escape(el.id);
        if (el.dataset && el.dataset.testid) return `[data-testid="${el.dataset.testid}"]`;

        // Priority 2: unique text content for buttons/links
        const tag = el.tagName.toLowerCase();
        if (['button', 'a', 'span', 'div', 'p', 'h1', 'h2', 'h3', 'h4', 'li'].includes(tag)) {
            const text = el.innerText?.trim();
            if (text && text.length < 50 && text.length > 0) {
                return `text=${JSON.stringify(text)}`;
            }
        }

        // Priority 3: input by placeholder or name
        if (tag === 'input' || tag === 'textarea') {
            if (el.placeholder) return `${tag}[placeholder="${el.placeholder}"]`;
            if (el.name) return `${tag}[name="${el.name}"]`;
            if (el.type) return `${tag}[type="${el.type}"]`;
        }

        // Priority 4: CSS path
        const path = [];
        let current = el;
        while (current && current !== document.body) {
            let segment = current.tagName.toLowerCase();
            if (current.className && typeof current.className === 'string') {
                const classes = current.className.trim().split(/\\s+/).filter(c => c.length > 0 && c.length < 30);
                if (classes.length > 0) {
                    segment += '.' + classes.slice(0, 2).map(c => CSS.escape(c)).join('.');
                }
            }
            path.unshift(segment);
            current = current.parentElement;
            if (path.length >= 4) break;
        }
        return path.join(' > ');
    }

    function emit(type, detail) {
        const data = {
            type: type,
            timestamp: Date.now() - startTime,
            url: location.href,
            ...detail
        };
        console.log('__RECORDER__:' + JSON.stringify(data));
    }

    // Click events
    document.addEventListener('click', (e) => {
        const el = e.target;
        const rect = el.getBoundingClientRect();
        emit('click', {
            selector: getSelector(el),
            tag: el.tagName.toLowerCase(),
            text: (el.innerText || '').trim().substring(0, 80),
            x: Math.round(e.clientX),
            y: Math.round(e.clientY),
            elementX: Math.round(rect.x),
            elementY: Math.round(rect.y),
            elementW: Math.round(rect.width),
            elementH: Math.round(rect.height)
        });
    }, true);

    // Input events (debounced)
    let inputTimers = new Map();
    document.addEventListener('input', (e) => {
        const el = e.target;
        const key = getSelector(el);
        if (inputTimers.has(key)) clearTimeout(inputTimers.get(key));
        inputTimers.set(key, setTimeout(() => {
            emit('input', {
                selector: key,
                tag: el.tagName.toLowerCase(),
                value: el.value,
                placeholder: el.placeholder || ''
            });
            inputTimers.delete(key);
        }, 500));
    }, true);

    // Keyboard: Enter and Escape
    document.addEventListener('keydown', (e) => {
        if (['Enter', 'Escape', 'Tab'].includes(e.key)) {
            emit('keydown', {
                key: e.key,
                selector: getSelector(e.target)
            });
        }
    }, true);

    // Scroll events (debounced)
    let scrollTimer = null;
    window.addEventListener('scroll', () => {
        if (scrollTimer) clearTimeout(scrollTimer);
        scrollTimer = setTimeout(() => {
            emit('scroll', {
                scrollX: Math.round(window.scrollX),
                scrollY: Math.round(window.scrollY)
            });
        }, 300);
    }, true);

    // Detect navigation via History API
    const origPush = history.pushState;
    const origReplace = history.replaceState;
    history.pushState = function() {
        origPush.apply(this, arguments);
        emit('navigation', { url: location.href, method: 'pushState' });
    };
    history.replaceState = function() {
        origReplace.apply(this, arguments);
        emit('navigation', { url: location.href, method: 'replaceState' });
    };
    window.addEventListener('popstate', () => {
        emit('navigation', { url: location.href, method: 'popstate' });
    });

    console.log('__RECORDER__:' + JSON.stringify({type: 'ready', timestamp: 0, url: location.href}));
})();
"""


class ActionRecorder:
    def __init__(self, cdp_url="http://localhost:9222", output_file=None):
        self.cdp_url = cdp_url
        self.output_file = output_file or f"recorded_{datetime.now().strftime('%Y%m%d_%H%M%S')}.py"
        self.events = []
        self.running = True
        self.page = None

    def _format_event(self, event):
        """Format a single event for display."""
        t = event.get("type", "?")
        ts = event.get("timestamp", 0)
        sec = ts / 1000

        if t == "click":
            text = event.get("text", "")[:40]
            sel = event.get("selector", "")
            return f"[{sec:6.1f}s] CLICK  {sel}  {f'({text})' if text else ''}"
        elif t == "input":
            sel = event.get("selector", "")
            val = event.get("value", "")[:40]
            return f"[{sec:6.1f}s] INPUT  {sel}  = \"{val}\""
        elif t == "keydown":
            return f"[{sec:6.1f}s] KEY    {event.get('key', '')}"
        elif t == "scroll":
            return f"[{sec:6.1f}s] SCROLL y={event.get('scrollY', 0)}"
        elif t == "navigation":
            return f"[{sec:6.1f}s] NAV    {event.get('url', '')}"
        elif t == "page_navigation":
            return f"[{sec:6.1f}s] PAGE   {event.get('url', '')}"
        elif t == "ready":
            return f"[{sec:6.1f}s] READY  Recording on {event.get('url', '')}"
        return f"[{sec:6.1f}s] {t}"

    def _generate_code(self):
        """Generate replayable Python code from recorded events."""
        lines = [
            '"""Auto-generated by recorder.py"""',
            "",
            "import asyncio",
            "from patchright.async_api import async_playwright",
            "",
            "",
            "async def replay(cdp_url='http://localhost:9222'):",
            "    p = await async_playwright().start()",
            "    browser = await p.chromium.connect_over_cdp(cdp_url)",
            "    context = browser.contexts[0]",
            "    page = context.pages[0] if context.pages else await context.new_page()",
            "",
        ]

        prev_ts = 0
        for ev in self.events:
            if ev["type"] in ("ready",):
                continue

            ts = ev.get("timestamp", 0)
            delay = ts - prev_ts
            if delay > 500:
                lines.append(f"    await asyncio.sleep({delay / 1000:.1f})")
            prev_ts = ts

            t = ev["type"]
            if t == "navigation" or t == "page_navigation":
                url = ev.get("url", "")
                lines.append(f"    await page.goto({url!r}, wait_until='domcontentloaded')")
            elif t == "click":
                sel = ev.get("selector", "")
                lines.append(f"    await page.locator({sel!r}).click()")
            elif t == "input":
                sel = ev.get("selector", "")
                val = ev.get("value", "")
                lines.append(f"    await page.locator({sel!r}).fill({val!r})")
            elif t == "keydown":
                key = ev.get("key", "")
                lines.append(f"    await page.keyboard.press({key!r})")
            elif t == "scroll":
                sy = ev.get("scrollY", 0)
                lines.append(f"    await page.evaluate('window.scrollTo(0, {sy})')")

        lines.extend([
            "",
            "",
            "if __name__ == '__main__':",
            "    asyncio.run(replay())",
            "",
        ])
        return "\n".join(lines)

    async def _on_console(self, msg):
        """Handle console messages from the injected recorder."""
        text = msg.text
        if not text.startswith("__RECORDER__:"):
            return
        try:
            data = json.loads(text[len("__RECORDER__:"):])
            self.events.append(data)
            print(self._format_event(data))
        except json.JSONDecodeError:
            pass

    async def _inject_recorder(self, page):
        """Inject the recorder script into a page."""
        try:
            await page.evaluate(RECORDER_JS)
        except Exception as e:
            print(f"  Warning: could not inject recorder into page: {e}")

    async def run(self):
        print(f"Connecting to Chrome at {self.cdp_url} ...")
        async with async_playwright() as p:
            browser = await p.chromium.connect_over_cdp(self.cdp_url)
            context = browser.contexts[0]

            # Inject into all existing pages
            for page in context.pages:
                page.on("console", self._on_console)
                page.on("framenavigated", lambda frame, pg=page: asyncio.ensure_future(self._on_frame_navigated(pg, frame)))
                await self._inject_recorder(page)
                print(f"  Attached to: {page.url}")

            # Handle new pages (tabs)
            def on_new_page(page):
                page.on("console", self._on_console)
                page.on("framenavigated", lambda frame, pg=page: asyncio.ensure_future(self._on_frame_navigated(pg, frame)))
                asyncio.ensure_future(self._inject_recorder(page))
                print(f"  New tab: {page.url}")

            context.on("page", on_new_page)

            print()
            print("=" * 60)
            print("  RECORDING — operate in Chrome normally")
            print("  Press Ctrl+C to stop and save")
            print("=" * 60)
            print()

            # Keep running until Ctrl+C
            try:
                while self.running:
                    await asyncio.sleep(0.5)
            except asyncio.CancelledError:
                pass

            # Save
            self._save()
            await browser.close()

    async def _on_frame_navigated(self, page, frame):
        """Re-inject recorder after navigation."""
        if frame == page.main_frame:
            self.events.append({
                "type": "page_navigation",
                "timestamp": int(time.time() * 1000) - (self.events[0]["timestamp"] if self.events else 0),
                "url": page.url
            })
            print(self._format_event(self.events[-1]))
            await asyncio.sleep(1)  # Wait for page load
            await self._inject_recorder(page)

    def _save(self):
        if not self.events:
            print("\nNo events recorded.")
            return

        # Save raw events as JSON
        json_file = self.output_file.replace(".py", ".json")
        with open(json_file, "w", encoding="utf-8") as f:
            json.dump(self.events, f, ensure_ascii=False, indent=2)
        print(f"\nRaw events saved to: {json_file}")

        # Save as Python code
        code = self._generate_code()
        with open(self.output_file, "w", encoding="utf-8") as f:
            f.write(code)
        print(f"Replay script saved to: {self.output_file}")
        print(f"Total events: {len(self.events)}")


def main():
    import argparse
    parser = argparse.ArgumentParser(description="Record browser actions via CDP")
    parser.add_argument("--cdp", default="http://localhost:9222", help="CDP endpoint")
    parser.add_argument("-o", "--output", default=None, help="Output file (default: recorded_<timestamp>.py)")
    args = parser.parse_args()

    recorder = ActionRecorder(cdp_url=args.cdp, output_file=args.output)

    loop = asyncio.new_event_loop()

    def handle_sigint(*_):
        recorder.running = False

    signal.signal(signal.SIGINT, handle_sigint)

    try:
        loop.run_until_complete(recorder.run())
    except KeyboardInterrupt:
        recorder._save()


if __name__ == "__main__":
    main()

