import asyncio
from patchright.async_api import async_playwright

DUMP_JS = """() => {
    function dump(el, depth, maxDepth) {
        if (depth > maxDepth || !el) return '';
        var tag = el.tagName ? el.tagName.toLowerCase() : '';
        if (!tag) return '';
        if (['script', 'style', 'svg', 'path', 'noscript', 'link', 'meta'].indexOf(tag) >= 0) return '';

        var id = el.id ? '#' + el.id : '';
        var cls = (el.className && typeof el.className === 'string')
            ? '.' + el.className.trim().split(/\\s+/).slice(0, 3).join('.')
            : '';
        var text = '';
        if (el.childNodes.length === 1 && el.childNodes[0].nodeType === 3) {
            var t = el.textContent.trim();
            if (t.length > 0 && t.length < 60) text = ' "' + t + '"';
        }
        var attrs = [];
        if (el.getAttribute('data-expect')) attrs.push('data-expect=' + el.getAttribute('data-expect'));
        if (el.getAttribute('data-jid')) attrs.push('data-jid=' + el.getAttribute('data-jid'));
        if (el.getAttribute('data-id')) attrs.push('data-id=' + el.getAttribute('data-id'));
        if (el.getAttribute('placeholder')) attrs.push('placeholder=' + el.getAttribute('placeholder'));
        if (el.getAttribute('role')) attrs.push('role=' + el.getAttribute('role'));
        if (el.getAttribute('href')) attrs.push('href=' + el.getAttribute('href').substring(0, 80));
        var attrStr = attrs.length ? ' [' + attrs.join(', ') + ']' : '';

        var indent = '';
        for (var i = 0; i < depth; i++) indent += '  ';
        var result = indent + tag + id + cls + attrStr + text + '\\n';

        var children = Array.from(el.children);
        var limit = children.length > 8 ? 4 : children.length;
        for (var j = 0; j < limit; j++) {
            result += dump(children[j], depth + 1, maxDepth);
        }
        if (children.length > limit) {
            result += indent + '  ... (' + (children.length - limit) + ' more children)\\n';
        }
        return result;
    }
    return dump(document.body, 0, 10);
}"""

SELECTORS_JS = """() => {
    var results = {};

    // Job selector / dropdown
    var jobSelects = document.querySelectorAll('select, [class*="job"], [class*="position"], [class*="dropdown"], [class*="select"]');
    results.job_selectors = [];
    jobSelects.forEach(function(el) {
        results.job_selectors.push({
            tag: el.tagName.toLowerCase(),
            class: el.className,
            id: el.id,
            html: el.outerHTML.substring(0, 300)
        });
    });

    // Filter area
    var filters = document.querySelectorAll('[class*="filter"], [class*="screen"], [class*="check"]');
    results.filters = [];
    filters.forEach(function(el) {
        results.filters.push({
            tag: el.tagName.toLowerCase(),
            class: el.className,
            html: el.outerHTML.substring(0, 200)
        });
    });

    // Candidate cards
    var cards = document.querySelectorAll('[class*="card"], [class*="geek"], [class*="candidate"], [class*="recommend"]');
    results.cards = [];
    cards.forEach(function(el) {
        if (results.cards.length < 5) {
            results.cards.push({
                tag: el.tagName.toLowerCase(),
                class: el.className,
                id: el.id,
                html: el.outerHTML.substring(0, 400)
            });
        }
    });

    // Greet / contact buttons
    var buttons = document.querySelectorAll('button, [class*="greet"], [class*="contact"], [class*="chat-btn"], [class*="say-hi"]');
    results.buttons = [];
    buttons.forEach(function(el) {
        if (results.buttons.length < 8) {
            results.buttons.push({
                tag: el.tagName.toLowerCase(),
                class: el.className,
                text: (el.innerText || '').trim().substring(0, 50),
                html: el.outerHTML.substring(0, 300)
            });
        }
    });

    // Links with data attributes
    var links = document.querySelectorAll('a[data-expect], a[data-jid], a[data-id]');
    results.data_links = [];
    links.forEach(function(el) {
        if (results.data_links.length < 5) {
            results.data_links.push({
                href: el.getAttribute('href'),
                'data-expect': el.getAttribute('data-expect'),
                'data-jid': el.getAttribute('data-jid'),
                'data-id': el.getAttribute('data-id'),
                class: el.className,
                html: el.outerHTML.substring(0, 300)
            });
        }
    });

    return JSON.stringify(results, null, 2);
}"""


async def inspect():
    p = await async_playwright().start()
    browser = await p.chromium.connect_over_cdp('http://localhost:9222')
    context = browser.contexts[0]
    page = context.pages[0] if context.pages else None
    if not page:
        print('No page found')
        return

    print(f'Current URL: {page.url}')
    print()

    # List frames
    frames = page.frames
    print(f'Frames ({len(frames)}):')
    for f in frames:
        print(f'  - name="{f.name or "(main)"}": {f.url}')
    print()

    # Get the recommendFrame
    rec_frame = page.frame(name='recommendFrame')
    if rec_frame:
        print('=== recommendFrame DOM ===')
        try:
            dom = await rec_frame.evaluate(DUMP_JS)
            print(dom[:8000])
        except Exception as e:
            print(f'Error dumping DOM: {e}')

        print()
        print('=== recommendFrame selectors ===')
        try:
            sels = await rec_frame.evaluate(SELECTORS_JS)
            print(sels[:8000])
        except Exception as e:
            print(f'Error checking selectors: {e}')
    else:
        print('recommendFrame not found, inspecting main page...')
        try:
            dom = await page.evaluate(DUMP_JS)
            print(dom[:8000])
        except Exception as e:
            print(f'Error: {e}')

    await browser.close()
    await p.stop()


asyncio.run(inspect())

